const express = require("express");
const app = express();
const server = require("http").Server(app); //import http module from 'http' 
const io = require("socket.io")(server);//import socket.io module for http 
app.use(express.static(__dirname + "/public"));//static folder as public
let port = process.env.PORT || 3000;
  app.get("/", function (req, res) {
    res.sendFile("index.html", { root: __dirname });
  });
io.on('connection',function(socket){ //When a connection happens, run the function
  socket.emit('greet','Welcome to Online Leaderboard Game');//Send message to client. Use the name greet as the event and send a welcome message 'welcome to Online Leaderboard Game'
});  server.listen(port); //start listening on port 3000